1813	**3. HTTP Cache Header Middleware**:
1814	```php
1815	// app/Http/Middleware/HttpCacheHeaders.php
1816	class HttpCacheHeaders
1817	{
1818	    private const IMMUTABLE_PATTERNS = [
1819	        'api/v5/support-service-groups',
1820	        'api/v5/worklog-activity-types',
1821	        'api/v5/support-sla-configs',
1822	    ];
1823	
1824	    public function handle(Request $request, Closure $next): Response
1825	    {
1826	        $response = $next($request);
1827	
1828	        if (!$request->isMethod('GET') || !$response->isSuccessful()) {
1829	            return $response;
1830	        }
1831	
1832	        // Static catalogs: cache 1 hour
1833	        foreach (self::IMMUTABLE_PATTERNS as $pattern) {
1834	            if ($request->is($pattern)) {
1835	                $response->headers->set('Cache-Control', 'public, max-age=3600, s-maxage=3600');
1836	                $response->headers->set('ETag', md5($response->getContent()));
1837	                return $response;
1838	            }
1839	        }
1840	
1841	        // User-specific data: private, short cache
1842	        $response->headers->set('Cache-Control', 'private, no-cache, must-revalidate');
1843	        $response->headers->set('Vary', 'Authorization, Cookie');
1844	
1845	        return $response;
1846	    }
1847	}
1848	```
