1912	### A15. Read Rate Limiting (HIGH — addresses ISSUE-22)
1913	
1914	**Problem**: Dashboard endpoints run 6-10 aggregate queries per request. At 2000 users polling every 30s = 4000 req/min → DB saturation even with cache.
1915	
1916	**Solution — Tiered Read Limits**:
1917	```php
1918	// AppServiceProvider.php
1919	RateLimiter::for('api.read', function (Request $request) {
1920	    $userId = $request->user()?->id ?? $request->ip();
1921	    return Limit::perMinute(120)->by("read:{$userId}");
1922	});
1923	
1924	RateLimiter::for('api.read.heavy', function (Request $request) {
1925	    $userId = $request->user()?->id ?? $request->ip();
1926	    return Limit::perMinute(30)->by("heavy-read:{$userId}");
1927	});
1928	
1929	RateLimiter::for('api.search', function (Request $request) {
1930	    $userId = $request->user()?->id ?? $request->ip();
1931	    return Limit::perMinute(60)->by("search:{$userId}");
1932	});
1933	```
1934	
1935	**Apply to routes**:
1936	```php
1937	// Heavy dashboard endpoints — 30 req/min
1938	Route::middleware('throttle:api.read.heavy')->group(function () {
1939	    Route::get('/fee-collection/dashboard', ...);
1940	    Route::get('/revenue/overview', ...);
1941	    Route::get('/leadership/dashboard', ...);
1942	    Route::get('/leadership/risks', ...);
1943	    Route::get('/customer-request-cases/dashboard/{role}', ...);
1944	});
1945	
1946	// Search endpoints — 60 req/min
1947	Route::middleware('throttle:api.search')->group(function () {
1948	    Route::get('/customer-request-cases/search', ...);
1949	});
1950	
1951	// Regular list GETs — 120 req/min
1952	Route::middleware('throttle:api.read')->group(function () {
1953	    // ... all other GET routes
1954	});
1955	```
